        "question": [
          "From history position and Trade position, can we understand in the last week, how many clicks did clients do. If a client opened and close (from History) it should double the click counds"
        ],
        "sql": [
          "WITH filtered_history AS (\n",
          "  SELECT\n",
          "    `CID`,\n",
          "    `RequestOpenOccurred`,\n",
          "    `RequestCloseOccurred`\n",
          "  FROM\n",
          "    `main`.`trading`.`bronze_etoro_history_position_datafactory`\n",
          "  WHERE\n",
          "    `RequestOpenOccurred` >= date_sub(current_date(), 7)\n",
          "    OR `RequestCloseOccurred` >= date_sub(current_date(), 7)\n",
          ")\n",
          "SELECT\n",
          "  `CID`,\n",
          "  COUNT(`RequestOpenOccurred`) + COUNT(`RequestCloseOccurred`) AS `click_count`\n",
          "FROM\n",
          "  filtered_history\n",
          "GROUP BY\n",
          "  `CID`"
        ]
      }
    ]
